const inp = $input.first().json;
const ctx = inp.context || {};
const emp = ctx.employee || {}, vio = ctx.violation || {}, mgr = ctx.manager || {};
const wp = ctx.workplace || {};
const wit = Array.isArray(ctx.witnesses) ? ctx.witnesses : [];
const w1 = wit[0] || {}, w2 = wit[1] || {};
const U = '[УТОЧНИТЬ]';
function ru(d){ const m = String(d||'').match(/^(\d{4})-(\d{2})-(\d{2})$/); return m ? `${m[3]}.${m[2]}.${m[1]}` : (d || U); }
const scenario = ctx.scenario || 'progul_ochny';
// какие документы нужны для сценария (расширяемо под новые проекты)
const DOC_MAP = {
  progul_ochny: { нужен_акт: true,  нужна_сз: true },
  zaglushka:    { нужен_акт: false, нужна_сз: true },
};
const docs = DOC_MAP[scenario] || { нужен_акт: true, нужна_сз: true };
const t = new Date();
const dd = String(t.getDate()).padStart(2,'0'), mm = String(t.getMonth()+1).padStart(2,'0'), yyyy = t.getFullYear();
const hh = String(t.getHours()).padStart(2,'0'), mi = String(t.getMinutes()).padStart(2,'0');
return [{ json: {
  нужен_акт: docs.нужен_акт,
  нужна_сз: docs.нужна_сз,
  акт_file_id: '1pz4mHqz6dleQKZvit3VRfXs_h95VWqKl',
  сз_file_id: '1iiqEDumDy61qRr9lv0kFGpkUB3hTpkWd',
  chat_id: inp.chat_id,
  // --- сырые поля для промпта Ollama (чтобы не было far-reference) ---
  contactAttempts: ctx.contactAttempts || '',
  respectableReason: !!ctx.respectableReason,
  respectableReasonComment: ctx.respectableReasonComment || '',
  evidenceDescription: ctx.evidenceDescription || '',
  // --- плейсхолдеры шаблонов (25) ---
  организация: 'АО «ПФ «СКБ Контур»',
  город: wp.city || U,
  адрес: wp.address || U,
  время_составления: `${hh}:${mi}`,
  дата_составления: `${dd}.${mm}.${yyyy}`,
  год: String(yyyy),
  дата_отсутствия: ru(vio.date),
  время_начала: vio.absenceStart || U,
  время_окончания: vio.absenceEnd || U,
  подразделение: emp.department || U,
  должность_работника: emp.position || U,
  фио_работника: emp.name || U,
  должность_составителя: mgr.position || U,
  фио_составителя: mgr.name || U,
  свидетель_1_фио: w1.name || U,
  свидетель_1_должность: w1.position || U,
  свидетель_2_фио: w2.name || U,
  свидетель_2_должность: w2.position || U,
  должность_руководителя_организации: 'Директору',
  фио_руководителя_организации: '',
  должность_автора: mgr.position || U,
  подразделение_автора: mgr.department || U,
  фио_автора: mgr.name || U,
} }];

const AdmZip = require('adm-zip');
const v = $('Объединить значения').first().json;
const SKIP = new Set(['chat_id']);
const inBin = $input.item.binary.data;
const fileName = (inBin && inBin.fileName) || 'Документ.docx';
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const zip = new AdmZip(buffer);
let xml = zip.readAsText('word/document.xml');
for (const [key, val] of Object.entries(v)) {
  if (SKIP.has(key) || key.endsWith('_file_id')) continue;
  xml = xml.split('{{' + key + '}}').join(String(val ?? ''));
}
zip.updateFile('word/document.xml', Buffer.from(xml, 'utf8'));
const out = zip.toBuffer();
const binary = await this.helpers.prepareBinaryData(out, fileName, 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');
return [{ json: { rendered: fileName }, binary: { data: binary } }];

// Чеклист подгружается ДИНАМИЧЕСКИ из Google Drive (нода «Drive: скачать чеклист»).
// Источник правды: knowledge/progul_checklist.md → выгружен в Google Drive
// (fileId 1AkZ9oCM6EzNHewmEiwqvERmq9cKDMt0V). Команда правит чеклист прямо в Drive.
// Сроки ст.193 здесь НЕ дублируются — они проверяются в main-агенте (calc_deadlines).
const AdmZip = require('adm-zip');
let checklist = '[чеклист не загружен из Drive]';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  if (buf && buf.length) {
    // Google Doc export=text/plain → обычный текст; .docx → zip (PK..) → достаём из word/document.xml
    if (buf[0] === 0x50 && buf[1] === 0x4B) {
      const zip = new AdmZip(buf);
      const xml = zip.readAsText('word/document.xml');
      checklist = xml.replace(/<\/w:p>/g, '\n').replace(/<[^>]+>/g, '').replace(/[ \t]+/g, ' ').trim();
    } else {
      checklist = buf.toString('utf8').replace(/^\uFEFF/, '').trim();
    }
  }
} catch (e) {
  checklist = '[ошибка загрузки чеклиста из Drive: ' + e.message + ']';
}

const d = $('Нормализовать данные').first().json;
return [{ json: { ...d, checklist_content: checklist } }];

const raw = $input.first().json;
let data = raw;
if (raw.query && typeof raw.query === 'object' && !Array.isArray(raw.query)) {
  data = raw.query;
} else if (typeof raw.input === 'string') {
  try { data = JSON.parse(raw.input); } catch(e) {}
} else if (typeof raw.query === 'string') {
  try { data = JSON.parse(raw.query); } catch(e) {}
}
if (!data.employee) throw new Error('hr_generate: не переданы данные employee. Получено: ' + JSON.stringify(raw));
if (!data.violation) throw new Error('hr_generate: не переданы данные violation.');
data.scenario = data.scenario || 'progul_ochny';
return [{ json: {
  context: data,
  chat_id: data.chat_id || raw.chat_id || null,
  evidence: data.evidence || raw.evidence || null,
  violationDate: data.violation.date,
  discoveryDate: data.violation.discoveryDate
} }];

// TODO: добавить knowledge-файлы и убрать эту заглушку
// Инструкция в sticky note «Добавить новый сценарий» (см. выше)
const d = $input.first().json;
const scenario = d.context?.scenario || 'unknown';
return [{ json: {
  ...d,
  checklist_content: `[ЗАГЛУШКА] Сценарий "${scenario}" не реализован. Добавьте knowledge/${scenario}_checklist.md`
} }];

// VISION STUB v1 — TODO: заменить на HTTP Request к vision-модели Ollama (qwen2-vl / llava)
// Интерфейс: принимает evidenceDescription, возвращает { vision_stub, analysis }
// При замене: убрать этот нод, добавить HTTP Request к http://127.0.0.1:11434/api/generate
// с моделью qwen2-vl и base64-изображением в поле images[]
const d = $input.first().json;
const desc = d.context?.evidenceDescription || 'Доказательства не предоставлены';
return [{ json: {
  ...d,
  vision_analysis: {
    vision_stub: true,
    analysis: desc,
    _note: 'STUB: заменить на реальную vision-модель Ollama'
  }
} }];

const r = $input.first().json;
const violations = r.response?.trim() || '[Не удалось сформулировать нарушение]';
const prev = $('Vision: анализ доказательств (заглушка)').first().json;
return [{ json: {
  context: prev.context,
  chat_id: prev.chat_id,
  dates: prev.dates,
  checklist_content: prev.checklist_content,
  vision_analysis: prev.vision_analysis,
  violations
} }];

const out = '✅ Готово! Акт об отсутствии и служебная записка сформированы и отправлены файлами выше.\n\n'
  + '⚠️ Проверьте документы и заполните поля [УТОЧНИТЬ] (свидетели, адрес, руководитель организации) перед подписанием.\n'
  + 'Передайте готовый пакет Черепановой Т. или Касмыниной О.';
return [{ json: { output: out } }];

const d = $input.first().json;
const ctx = d.context;
const prompt = `Ты — юридический ассистент по трудовому праву. Твоя задача — кратко и точно сформулировать нарушение трудовых обязанностей со ссылками на нормативные акты.

## Данные о нарушении
Сотрудник: ${ctx.employee?.name || '[не указано]'}
Должность: ${ctx.employee?.position || '[не указано]'}
Подразделение: ${ctx.employee?.department || '[не указано]'}
Дата нарушения: ${ctx.violation?.date || '[не указано]'}
Описание: ${ctx.violation?.description || 'Прогул — отсутствие на рабочем месте без уважительной причины'}
Уважительная причина: ${ctx.respectableReason ? 'Есть: ' + ctx.respectableReasonComment : 'Отсутствует'}

## Чеклист (внутренняя инструкция)
${d.checklist_content}

## Задача
Сформулируй нарушение в 2-4 предложениях для включения в служебную записку. Укажи конкретные статьи, пункты. Формат: юридически грамотно, сухо, без лишних слов.
Отвечай ТОЛЬКО формулировкой нарушения, без вводных фраз.`;
return [{ json: { ...d, prompt_rag: prompt } }];

// petrovich — опционально: если установлен, склоняем им (точнее), иначе fallback на JS-правилах
let petrovich = null;
try { petrovich = require('petrovich'); } catch (e) { petrovich = null; }

const base = $input.first().json;
const U = '[УТОЧНИТЬ]';

// --- fallback-склонение в дательный (без библиотеки) ---
const FLEET_M = { 'Павел':'Павлу','Пётр':'Петру','Петр':'Петру','Лев':'Льву' };
const datWordM = w => FLEET_M[w] ? FLEET_M[w]
  : /[ая]$/.test(w) ? w.slice(0,-1)+'е'
  : /й$/.test(w)    ? w.slice(0,-1)+'ю'
  : /ь$/.test(w)    ? w.slice(0,-1)+'ю'
  : w+'у';
const datWordF = w => /ия$/.test(w) ? w.slice(0,-2)+'ии'
  : /[ая]$/.test(w) ? w.slice(0,-1)+'е'
  : /ь$/.test(w)    ? w.slice(0,-1)+'и'
  : w;
const datLastM = w => /(ский|цкий)$/.test(w) ? w.slice(0,-2)+'ому'
  : /ой$/.test(w)            ? w.slice(0,-2)+'ому'
  : /(ый|ий)$/.test(w)       ? w.slice(0,-2)+'ому'
  : /(ов|ев|ёв|ин|ын)$/.test(w) ? w+'у'
  : /[бвгджзклмнпрстфхцчшщ]$/.test(w) ? w+'у'
  : w;
const datLastF = w => /(ова|ева|ёва|ина|ына)$/.test(w) ? w.slice(0,-1)+'ой'
  : /(ская|цкая)$/.test(w) ? w.slice(0,-2)+'ой'
  : w;
const datMid = w => /(ович|евич|ич)$/.test(w) ? w+'у'
  : /(овна|евна|ична|инична)$/.test(w) ? w.slice(0,-1)+'е'
  : w;
function fallbackDat(last, first, middle){
  const m = (middle||'').toLowerCase();
  const fem = /(вна|чна)$/.test(m);
  const L = fem ? datLastF(last) : datLastM(last);
  const F = first  ? (fem ? datWordF(first) : datWordM(first)) : '';
  const M = middle ? datMid(middle) : '';
  return [L,F,M].filter(Boolean).join(' ');
}

// --- склонение ФИО работника в ДАТЕЛЬНЫЙ падеж («применить к кому») ---
function sklonDat(fullname){
  const s = String(fullname||'').trim();
  if (!s || s === U) return s || U;
  const p = s.split(/\s+/);
  const last = p[0], first = p[1], middle = p[2];
  if (petrovich){
    const m = (middle||'').toLowerCase();
    let gender = 'androgynous';
    if (/(вна|чна)$/.test(m)) gender = 'female';
    else if (/(вич|ич)$/.test(m)) gender = 'male';
    try {
      const r = petrovich({ first, last, middle, gender }, 'dative');
      return [r.last, r.first, r.middle].filter(Boolean).join(' ');
    } catch (e) { /* падаем во fallback */ }
  }
  return fallbackDat(last, first, middle);
}
const дат = sklonDat(base.фио_работника);

// --- обстоятельства: склейка попыток связи + уважительной причины ---
let обст = String(base.contactAttempts||'').trim();
const прич = String(base.respectableReasonComment||'').trim();
if (base.respectableReason && прич) {
  обст += (обст?' ':'') + 'Уважительная причина: ' + прич + (/[.!?]$/.test(прич)?'':'.');
} else {
  обст += (обст?' ':'') + 'Уважительная причина не установлена.';
}
if (!обст.trim()) обст = U;

// --- приложения: нумерованный список из описания доказательств ---
const ev = String(base.evidenceDescription||'').trim();
let прил;
if (!ev) {
  прил = 'Отсутствуют';
} else {
  const lines = ev.split(/[\n;]+/).map(x => x.trim()).filter(Boolean);
  прил = lines.map((l,i) => `${i+1}. ${l}`).join('\n');
}

return [{ json: {
  ...base,
  фио_работника_дат: дат,
  фио_работника_род: дат,   // legacy-дубль: пока шаблон в Drive со старым ключом {{фио_работника_род}}. Убрать после правки Drive.
  обстоятельства: обст,
  приложения: прил,
} }];

const AdmZip = require('adm-zip');
const v = $('Объединить значения').first().json;
const SKIP = new Set(['chat_id']);
const inBin = $input.item.binary && $input.item.binary.data;
const fileName = (inBin && inBin.fileName) || 'Служебная записка.docx';
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const zip = new AdmZip(buffer);
let xml = zip.readAsText('word/document.xml');

// текстовые плейсхолдеры (кроме скриншотов — их обрабатываем отдельно)
for (const [key, val] of Object.entries(v)) {
  if (SKIP.has(key) || key.endsWith('_file_id') || key === 'скриншоты') continue;
  xml = xml.split('{{' + key + '}}').join(String(val ?? ''));
}

// --- собрать фото кейса (по порядку evidenceFiles от агента) ---
let photos = [];
try {
  const rows = $('Postgres: фото кейса').all().map(i => i.json);
  const ctx = ($('Нормализовать данные').first().json.context) || {};
  const order = Array.isArray(ctx.evidenceFiles) ? ctx.evidenceFiles : [];
  const byId = {};
  for (const r of rows) if (r.file_b64) byId[r.file_id] = r.file_b64;
  photos = order.length ? order.filter(id => byId[id]).map(id => byId[id])
                        : rows.filter(r => r.file_b64).map(r => r.file_b64);
} catch (e) { photos = []; }

// --- размеры изображения ---
function jpegSize(b){ let i=2; while(i<b.length-1){ if(b[i]!==0xFF){i++;continue;} const m=b[i+1];
  if(m>=0xC0&&m<=0xCF&&m!==0xC4&&m!==0xC8&&m!==0xCC) return {h:b.readUInt16BE(i+5),w:b.readUInt16BE(i+7)};
  if(m===0xD8||m===0xD9||(m>=0xD0&&m<=0xD7)){i+=2;continue;} i+=2+b.readUInt16BE(i+2);} return null; }
function imgSize(b){ if(b[0]===0xFF&&b[1]===0xD8) return jpegSize(b);
  if(b[0]===0x89&&b[1]===0x50) return {w:b.readUInt32BE(16),h:b.readUInt32BE(20)}; return null; }

if (photos.length) {
  let rels = zip.readAsText('word/_rels/document.xml.rels');
  let ct = zip.readAsText('[Content_Types].xml');
  const MAXW = 5486400; // ~6"
  let blocks = '';
  photos.forEach((b64, idx) => {
    const n = idx + 1;
    const buf = Buffer.from(b64, 'base64');
    const isPng = buf[0] === 0x89 && buf[1] === 0x50;
    const ext = isPng ? 'png' : 'jpeg';
    const ctype = isPng ? 'image/png' : 'image/jpeg';
    const rid = 'rIdEv' + n, fn = 'evidence' + n + '.' + ext, did = 1000 + n;
    zip.addFile('word/media/' + fn, buf);
    rels = rels.replace('</Relationships>',
      '<Relationship Id="' + rid + '" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="media/' + fn + '"/></Relationships>');
    if (ct.indexOf('Extension="' + ext + '"') === -1)
      ct = ct.replace('</Types>', '<Default Extension="' + ext + '" ContentType="' + ctype + '"/></Types>');
    const sz = imgSize(buf) || { w: 800, h: 600 };
    let ew = sz.w * 9525, eh = sz.h * 9525;
    if (ew > MAXW) { eh = Math.round(eh * MAXW / ew); ew = MAXW; }
    blocks +=
      '<w:p><w:r><w:rPr><w:b w:val="0"/></w:rPr><w:t>Скриншот ' + n + '</w:t></w:r></w:p>' +
      '<w:p><w:r><w:drawing><wp:inline distT="0" distB="0" distL="0" distR="0">' +
      '<wp:extent cx="' + ew + '" cy="' + eh + '"/><wp:effectExtent l="0" t="0" r="0" b="0"/>' +
      '<wp:docPr id="' + did + '" name="Screenshot' + n + '"/>' +
      '<a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main">' +
      '<a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture">' +
      '<pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture">' +
      '<pic:nvPicPr><pic:cNvPr id="' + did + '" name="Screenshot' + n + '"/><pic:cNvPicPr/></pic:nvPicPr>' +
      '<pic:blipFill><a:blip r:embed="' + rid + '"/><a:stretch><a:fillRect/></a:stretch></pic:blipFill>' +
      '<pic:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="' + ew + '" cy="' + eh + '"/></a:xfrm>' +
      '<a:prstGeom prst="rect"><a:avLst/></a:prstGeom></pic:spPr>' +
      '</pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p>';
  });
  xml = xml.split('{{скриншоты}}').join(blocks);
  zip.updateFile('word/_rels/document.xml.rels', Buffer.from(rels, 'utf8'));
  zip.updateFile('[Content_Types].xml', Buffer.from(ct, 'utf8'));
} else {
  xml = xml.split('{{скриншоты}}').join('');
}

zip.updateFile('word/document.xml', Buffer.from(xml, 'utf8'));
const out = zip.toBuffer();
const binary = await this.helpers.prepareBinaryData(out, fileName, 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');
return [{ json: { rendered: fileName, screenshots: photos.length }, binary: { data: binary } }];
